var e=[{id:`L2_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`영...... 차.`,JPN:`よいしょっと……`,ENG:`Oof, this is pretty heavy.`,TWN:`赫……哈。`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`JIHUN_MILITIA_NULL_NULL`,text:{KOREA:`대체 배낭에 뭘 얼마나 쑤셔 박은 거야?`,JPN:`いったい何をどんだけカバンに詰め込んだんだ？`,ENG:`How much did you stuff inside the backpack?`,TWN:`妳到底往背包裡裝了多少東西？`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JIHUN_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`JIHUN_MILITIA_NULL_NULL`,text:{KOREA:`어린 게 욕심만 가득 차서는...... 그거 꺼내 쓸 수는 있냐?`,JPN:`ガキが欲張りやがって……そもそも使えるのか？`,ENG:`You greedy little thing... Can you even take anything out of that?`,TWN:`小小年紀就這麼貪……那麼多東西妳用得到嗎？`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JIHUN_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`신경 꺼. 할 수만 있으면 미사일이라도 챙겨 가고 싶으니까.`,JPN:`余計なお世話だ。できることならミサイルでも持っていきたい。`,ENG:`Mind your own beeswax. I'd even take a missile launcher if I could.`,TWN:`別多管閒事，如果可以的話，我甚至連導彈都想帶上。`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JIHUN_MILITIA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`DEALER_NPC_MILITIA_NULL`,text:{KOREA:`뭐야, 벌써 가려고? 데이터는?`,JPN:`もう行くのか？　データは？`,ENG:`Leaving so soon? What about the data?`,TWN:`怎麼，這麼快就要走？數據呢？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`너무 오래 머물렀다간 놈들에게 덜미를 잡힐 수 있어.`,JPN:`あまり長居したら、奴らにバレるリスクが高まる。`,ENG:`They might get to us if we stay in one spot for too long.`,TWN:`逗留太久會被敵人發現的。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`나중에 다시 연락하지.`,JPN:`あとでまた連絡する。`,ENG:`We'll be in touch.`,TWN:`我們日後再聯繫。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`그리고 우리가 왔었다는 건 비밀로 해 줬으면 좋겠군.`,JPN:`あと俺たちが来たことは内緒にしてほしい。`,ENG:`By the way, I hope you can exercise some discretion about our visit here.`,TWN:`今天的事情，希望你能保密。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`DEALER_NPC_MILITIA_NULL`,text:{KOREA:`정보 파는 놈에게 비밀이 어디 있어? 내 목숨 위험하면 다 불 거다.`,JPN:`情報屋に内緒なんかあるもんか！　ワシの命が危うくなったら全部バラすからな。`,ENG:`I sell information for a living and you expect me to keep this a secret? I'll rat you kids out the minute my life is on the line.`,TWN:`我可是靠販賣情報混飯吃的，哪有什麼秘密？如果有危險，我隨時會說出去。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`훗, 그러든지.`,JPN:`ふっ、好きにしろ。`,ENG:`Hah. Suit yourself.`,TWN:`呵呵，隨你。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`DEALER_NPC_MILITIA_NULL`,text:{KOREA:`어라, 새로운 손님이로군. 뭐 찾는 거라도 있소, 손님?`,JPN:`おや、新しいお客様か。何かお探しかね、お客様？`,ENG:`Oh, here's another customer. Looking for anything in particular, sir?`,TWN:`唉，客人來了。您找什麼呀，顧客？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`저 녀석은......?`,JPN:`あいつは……？`,ENG:`Wait, isn't he...`,TWN:`那傢伙是……？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DEALER_NPC_MILITIA_NULL`,text:{KOREA:`자동 권총? 아니면 연막탄?`,JPN:`自動拳銃？　それとも煙幕弾？`,ENG:`Automatic pistols? Or how about some smoke grenades?`,TWN:`自動手槍？或者煙霧彈？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`아니, 그런 것들보다 좀 더 살아서 펄떡이는 걸 찾으러 왔지.`,JPN:`いや、そんなものよりもっとイケてるものを探しに来たぜ。`,ENG:`No thanks. I'm actually looking for something more... alive.`,TWN:`不，我不找武器，我在找活蹦亂跳的活人。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SEONGTAE_MILITIA_NULL_NULL`,text:{KOREA:`손님이 아냐! 다들 피해!`,JPN:`客じゃない！　逃げろ！`,ENG:`He's not a customer! Everyone, get away!`,TWN:`他不是顧客！快跑！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SEONGTAE_MILITIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JIHUN_MILITIA_NULL_NULL`,text:{KOREA:`크헉......?!`,JPN:`ぐはっ……！`,ENG:`Hngh!`,TWN:`呃……？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}}];export{e as default};